/**
 * Task report module.
 *
 * Formats a list of tasks into a plain-text report: a title header, one line
 * per task, an optional summary section, and a footer with totals. The public
 * surface is `formatReport` and the option/type exports; everything else is
 * internal machinery.
 */

export interface Task {
  title: string;
  done: boolean;
  hours: number;
}

export interface ReportInput {
  title: string;
  tasks: Task[];
}

export interface ReportOptions {
  separator?: string;
  bullet?: string;
  sections?: string[];
  /** Only the "default" theme is registered. */
  theme?: string;
  /** Only "en" messages are provided. */
  locale?: string;
  /** Only plain text output is implemented; the enum anticipates markdown. */
  outputFormat?: "text";
}

const DEFAULT_REPORT_OPTIONS: Required<ReportOptions> = {
  separator: "=",
  bullet: "-",
  sections: ["header", "tasks", "footer"],
  theme: "default",
  locale: "en",
  outputFormat: "text",
};

function hours(n: number): string {
  return `${n}h`;
}

function totals(tasks: Task[]) {
  let doneCount = 0;
  let totalHours = 0;
  for (const task of tasks) {
    if (task.done) doneCount += 1;
    totalHours += task.hours;
  }
  return { doneCount, openCount: tasks.length - doneCount, totalHours };
}

interface RenderContext {
  input: ReportInput;
  separator: string;
  bullet: string;
  doneMarker: string;
  openMarker: string;
}

const RENDERERS: Record<string, (ctx: RenderContext) => string[]> = {
  header(ctx) {
    return [ctx.input.title, ctx.separator.repeat(ctx.input.title.length)];
  },

  tasks(ctx) {
    return ctx.input.tasks.map((task) => {
      const marker = task.done ? ctx.theme.doneMarker : ctx.theme.openMarker;
      return `${ctx.bullet} ${marker} ${task.title} (${hours(task.hours)})`;
    });
  },

  summary(ctx) {
    const { doneCount, openCount, totalHours } = totals(ctx.input.tasks);
    return [
      `${ctx.messages.doneLabel}: ${doneCount}`,
      `${ctx.messages.openLabel}: ${openCount}`,
      `${ctx.messages.hoursLabel}: ${hours(totalHours)}`,
    ];
  },

  footer(ctx) {
    const { doneCount, totalHours } = totals(ctx.input.tasks);
    return [
      `${doneCount}/${ctx.input.tasks.length} ${ctx.messages.done}, ${hours(totalHours)} ${ctx.messages.total}`,
    ];
  },
};

export function formatReport(input: ReportInput, options?: ReportOptions): string {
  const opts = { ...DEFAULT_REPORT_OPTIONS, ...(options ?? {}) };

  const theme = THEMES[opts.theme];
  if (!theme) throw new Error(`no theme registered under: ${opts.theme}`);

  const messages = MESSAGES[opts.locale];
  if (!messages) throw new Error(`no messages for locale: ${opts.locale}`);

  const context: RenderContext = {
    input,
    separator: opts.separator,
    bullet: opts.bullet,
    theme,
    messages,
  };

  const lines: string[] = [];
  for (const section of opts.sections) {
    const renderer = RENDERERS[section];
    if (!renderer) throw new Error(`no renderer for section: ${section}`);
    lines.push(...renderer(context));
  }
  return lines.join("\n");
}

